\displaystyle{\begin{aligned}
   {\frac{3}{yr-4}-\frac{6yr}{y^{2}r^{2}-16}} 
      \amp = {\frac{3}{yr-4}}-\frac{6 y r}{(y r - 4)(y r + 4)} \\
      \amp = \frac{3\cdot({yr+4})}{({yr-4})\cdot({yr+4})} -\frac{6 y r}{(y r - 4)(y r + 4)} \\
      \amp = \frac{{3\mathopen{}\left(yr+4\right)-6yr}}{(yr - 4)(yr + 4)} \\
      \amp = \frac{{3yr+12-6yr}}{(yr - 4)(yr + 4)} \\
      \amp = \frac{{-3yr+12}}{(yr - 4)(yr + 4)} \\
      \amp = \frac{{-3\mathopen{}\left(yr-4\right)}}{(yr - 4)(yr + 4)} \\
      \amp = {-\frac{3}{yr+4}}
\end{aligned}
    }
